import base64
from google.cloud import pubsub_v1

def process_message(message):
    """Processes a Pub/Sub message containing serialized Python objects."""
    try:
        data = base64.b64decode(message.data).decode('utf-8')
        deserialized_data = eval(data)  # Using eval instead of pickle.loads due to security concerns
        # Process the deserialized data, this could be any business logic you need to execute
        print(deserialized_data)
    except Exception as e:
        print(f"Error processing message: {str(e)}")

def pull_messages(project_id, topic_name):
    """Pulls messages from a Pub/Sub topic and processes them."""
    subscriber = pubsub_v1.SubscriberClient()
    subscription_path = f"projects/{project_id}/subscriptions/{topic_name}"
    
    response = subscriber.pull(subscription=subscription_path)
    
    if response.received_messages:
        for message in response.received_messages:
            process_message(message.message)
        
        # Acknowledge the messages
        subscriber.acknowledge(subscription=subscription_path, 
                              received_messages=[pubsub_v1.types.AcknowledgeRequest.MessageAcknowledgePayload(message=message) for message in response.received_messages])
    else:
        print("No messages received.")

def pull_and_process_jobs():
    project_id = "your-project-id"
    topic_name = "your-topic-name"
    
    while True:
        try:
            pull_messages(project_id, topic_name)
        except Exception as e:
            print(f"Error pulling messages: {str(e)}")